function CertCard({ cert, index }) {
  const [hovered, setHovered] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [ref, visible] = useInView(0.1);

  return (
    <>
      {/* Modal */}
      {modalOpen && (
        <div
          onClick={() => setModalOpen(false)}
          style={{
            position: "fixed", inset: 0, zIndex: 999,
            background: "rgba(0,0,0,0.85)", backdropFilter: "blur(8px)",
            display: "flex", alignItems: "center", justifyContent: "center",
            padding: 24,
            animation: "fadeIn 0.2s ease forwards",
          }}
        >
          <div style={{ position: "relative", maxWidth: 780, width: "100%" }}>
            <img
              src={cert.img}
              alt={cert.title}
              style={{ width: "100%", borderRadius: 16, boxShadow: "0 40px 100px rgba(0,0,0,0.8)" }}
              onClick={e => e.stopPropagation()}
            />
            <button
              onClick={() => setModalOpen(false)}
              style={{
                position: "absolute", top: -16, right: -16,
                width: 36, height: 36, borderRadius: "50%",
                background: "#1e293b", border: "1px solid rgba(255,255,255,0.1)",
                color: "#94a3b8", fontSize: 18, cursor: "pointer",
                display: "flex", alignItems: "center", justifyContent: "center",
              }}
            >×</button>
          </div>
        </div>
      )}

      {/* Card */}
      <div
        ref={ref}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
        onClick={() => setModalOpen(true)}
        style={{
          background: "rgba(13,14,20,0.9)",
          border: `1px solid ${hovered ? cert.accent + "55" : "rgba(255,255,255,0.06)"}`,
          borderRadius: 20, overflow: "hidden", cursor: "pointer",
          transition: "all 0.4s cubic-bezier(.25,.8,.25,1)",
          transform: visible ? (hovered ? "translateY(-8px)" : "translateY(0)") : "translateY(40px)",
          opacity: visible ? 1 : 0,
          transitionDelay: `${index * 0.12}s`,
          boxShadow: hovered
            ? `0 32px 64px rgba(0,0,0,0.5), 0 0 0 1px ${cert.accent}33`
            : "0 8px 24px rgba(0,0,0,0.3)",
        }}
      >
        {/* Certificate Preview */}
        <div style={{
          height: 180, overflow: "hidden", position: "relative",
          background: "#f8fafc",
        }}>
          <img
            src={cert.img}
            alt={cert.title}
            style={{
              width: "100%", height: "100%", objectFit: "cover", objectPosition: "top",
              transition: "transform 0.5s ease",
              transform: hovered ? "scale(1.06)" : "scale(1)",
            }}
          />
          {/* Overlay on hover */}
          <div style={{
            position: "absolute", inset: 0,
            background: "rgba(0,0,0,0.45)",
            display: "flex", alignItems: "center", justifyContent: "center",
            opacity: hovered ? 1 : 0,
            transition: "opacity 0.3s",
          }}>
            <span style={{
              fontFamily: "'JetBrains Mono', monospace", fontSize: 13,
              color: "#fff", letterSpacing: "0.08em",
              border: "1px solid rgba(255,255,255,0.4)",
              padding: "8px 20px", borderRadius: 8,
            }}>🔍 View Certificate</span>
          </div>
          {/* Level badge */}
          <div style={{
            position: "absolute", top: 12, right: 12,
            background: cert.accent + "ee",
            borderRadius: 6, padding: "4px 12px",
            fontFamily: "'JetBrains Mono', monospace", fontSize: 11,
            color: "#fff", fontWeight: 600, letterSpacing: "0.06em",
            boxShadow: `0 4px 12px ${cert.accent}66`,
          }}>{cert.level}</div>
        </div>

        {/* Card body */}
        <div style={{ padding: "20px 22px 24px" }}>
          {/* HackerRank logo text */}
          <div style={{
            display: "flex", alignItems: "center", gap: 8, marginBottom: 12,
          }}>
            <div style={{
              width: 28, height: 28, borderRadius: 6,
              background: "#1a1a2e",
              display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: 14, fontWeight: 800, color: "#22c55e",
              fontFamily: "'Syne', sans-serif",
            }}>H</div>
            <span style={{
              fontFamily: "'JetBrains Mono', monospace", fontSize: 11,
              color: "#475569", letterSpacing: "0.06em",
            }}>HackerRank</span>
          </div>

          <h3 style={{
            fontFamily: "'Syne', sans-serif", fontWeight: 700,
            fontSize: 17, color: "#f1f5f9", marginBottom: 8, lineHeight: 1.3,
          }}>{cert.title}</h3>

          <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
            <div style={{
              display: "flex", alignItems: "center", gap: 8,
              fontFamily: "'JetBrains Mono', monospace", fontSize: 11, color: "#475569",
            }}>
              <span style={{ color: cert.accent }}>📅</span>
              Earned: {cert.date}
            </div>
            <div style={{
              display: "flex", alignItems: "center", gap: 8,
              fontFamily: "'JetBrains Mono', monospace", fontSize: 10, color: "#334155",
            }}>
              <span style={{ color: "#475569" }}>ID:</span>
              {cert.id}
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

